        val discoveredDevices = mutableListOf<IoTDevice>()
        val scanClient = OkHttpClient.Builder()
            .connectTimeout(2, TimeUnit.SECONDS)
            .readTimeout(2, TimeUnit.SECONDS)
            .connectionSpecs(listOf(ConnectionSpec.CLEARTEXT))
            .build()

        var remaining = endHost - startHost + 1

        for (i in startHost..endHost) {
            val ip = "$subnet.$i"
            val url = "http://$ip:$port$path"
            val request = Request.Builder().url(url).get().build()

            scanClient.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    synchronized(discoveredDevices) {
                        remaining--
                        if (remaining == 0) {
                            callback.onDiscoveryComplete(discoveredDevices.toList())
