    // ==================== Builder ====================

    class Builder {
        private var cloudBaseUrl: String = CLOUD_BASE_URL
        private var cloudTimeoutSeconds: Long = 30
        private var localTimeoutSeconds: Long = 10
        private var authToken: String? = null
        private var additionalCloudHeaders: Map<String, String> = emptyMap()
        private var certificatePins: Map<String, String> = emptyMap()

        fun cloudBaseUrl(url: String) = apply { this.cloudBaseUrl = url }
        fun cloudTimeout(seconds: Long) = apply { this.cloudTimeoutSeconds = seconds }
        fun localTimeout(seconds: Long) = apply { this.localTimeoutSeconds = seconds }
        fun authToken(token: String) = apply { this.authToken = token }
        fun additionalCloudHeaders(headers: Map<String, String>) = apply {
            this.additionalCloudHeaders = headers
        }
        fun certificatePins(pins: Map<String, String>) = apply {
            this.certificatePins = pins
        }

        fun build(): IoTHttpClient {
            val loggingInterceptor = HttpLoggingInterceptor().apply {
                level = HttpLoggingInterceptor.Level.BODY
            }

            val pinnerBuilder = CertificatePinner.Builder()
            certificatePins.forEach { (host, pin) ->
                pinnerBuilder.add(host, pin)
            }

            val cloudClientBuilder = OkHttpClient.Builder()
                .connectTimeout(cloudTimeoutSeconds, TimeUnit.SECONDS)
                .readTimeout(cloudTimeoutSeconds, TimeUnit.SECONDS)
                .writeTimeout(cloudTimeoutSeconds, TimeUnit.SECONDS)
                .addInterceptor(loggingInterceptor)
                .addInterceptor(CloudApiInterceptor())
                .connectionSpecs(
                    listOf(ConnectionSpec.MODERN_TLS, ConnectionSpec.COMPATIBLE_TLS)
                )
                .certificatePinner(pinnerBuilder.build())

            if (authToken != null || additionalCloudHeaders.isNotEmpty()) {
                cloudClientBuilder.addInterceptor(Interceptor { chain ->
                    val builder = chain.request().newBuilder()
                    authToken?.let { builder.addHeader("Authorization", "Bearer $it") }
                    additionalCloudHeaders.forEach { (k, v) -> builder.addHeader(k, v) }
                    chain.proceed(builder.build())
                })
            }

            val localClientBuilder = OkHttpClient.Builder()
                .connectTimeout(localTimeoutSeconds, TimeUnit.SECONDS)
                .readTimeout(localTimeoutSeconds, TimeUnit.SECONDS)
                .writeTimeout(localTimeoutSeconds, TimeUnit.SECONDS)
                .addInterceptor(loggingInterceptor)
                .addInterceptor(LocalNetworkGuardInterceptor())
                .connectionSpecs(
                    listOf(
                        ConnectionSpec.MODERN_TLS,
                        ConnectionSpec.COMPATIBLE_TLS,
                        ConnectionSpec.CLEARTEXT
                    )
                )
                .followRedirects(false)

            return IoTHttpClient(cloudClientBuilder.build(), localClientBuilder.build())
        }
    }
