// ==================== Usage Example ====================

class IoTClientUsageExample {

    private val client = IoTHttpClient.getInstance()

    // Alternative: use the builder for custom configuration
    private val customClient = IoTHttpClient.Builder()
        .cloudTimeout(60)
        .localTimeout(5)
        .authToken("my-jwt-token")
        .additionalCloudHeaders(mapOf("X-App-Version" to "1.0.0"))
        .build()

    fun fetchCloudDeviceList(authToken: String) {
        client.cloudGet(
            endpoint = "/v1/devices",
            authToken = authToken,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    println("Cloud devices: ${response.body}")
                }

                override fun onError(error: Exception) {
                    println("Cloud error: ${error.message}")
                }
            }
        )
    }

    fun controlLocalDevice(deviceIp: String) {
        client.localPost(
            deviceIp = deviceIp,
            port = 80,
            path = "/api/control",
            body = """{"action": "toggle", "state": true}""",
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    println("Device response: ${response.body}")
                }

                override fun onError(error: Exception) {
                    println("Device error: ${error.message}")
                }
            }
        )
    }

    fun getLocalDeviceStatus(deviceIp: String) {
        client.localGet(
            deviceIp = deviceIp,
            port = 80,
            path = "/status",
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    println("Device status: ${response.body}")
                }

                override fun onError(error: Exception) {
                    println("Status error: ${error.message}")
                }
            }
        )
    }

    fun registerDeviceWithCloud(authToken: String, deviceInfo: String) {
        client.cloudPost(
            endpoint = "/v1/devices/register",
            jsonBody = deviceInfo,
            authToken = authToken,
            callback = object : IoTHttpClient.ApiCallback {
                override fun onSuccess(response: IoTHttpClient.ApiResponse) {
                    println("Registered: ${response.body}")
                }

                override fun onError(error: Exception) {
                    println("Registration error: ${error.message}")
                }
            }
        )
    }

    fun discoverLocalDevices() {
        client.discoverDevices(
            subnet = "192.168.1",
            port = 80,
            path = "/status",
            callback = object : IoTHttpClient.DeviceDiscoveryCallback {
                override fun onDeviceFound(device: IoTHttpClient.IoTDevice) {
                    println("Found device at ${device.ip}:${device.port}")
                }

                override fun onDiscoveryComplete(devices: List<IoTHttpClient.IoTDevice>) {
                    println("Discovery complete. Found ${devices.size} devices.")
                }
            }
        )
    }
}